import logging
from azure.functions import HttpRequest, HttpResponse

def main(req: HttpRequest) -> HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Process the payment notification here
    payment_data = req.get_json()
    if not payment_data:
        return HttpResponse(status_code=400, body='Invalid payment data')

    # Example processing logic
    amount = payment_data.get('amount')
    currency = payment_data.get('currency')
    transaction_id = payment_data.get('transactionId')

    logging.info(f'Received payment notification: Amount={amount}, Currency={currency}, Transaction ID={transaction_id}')

    return HttpResponse(status_code=200, body='Payment notification processed successfully', mimetype='application/json')